import time
import random
import numpy as np

def validate_inputs(inputs):
    # Validate inputs
    if not isinstance(inputs, list) or len(inputs)!= 2:
        raise ValueError("Invalid input type")
    if not all(isinstance(x, (int, float)) for x in inputs):
        raise

